/// A data structure to hold MTP device entries.
final class LIBMTP_device_entry_struct extends ffi.Struct {
  /// < The vendor of this device
  external ffi.Pointer<ffi.Char> vendor;

  /// < Vendor ID for this device
  @ffi.Uint16()
  external int vendor_id;

  /// < The product name of this device
  external ffi.Pointer<ffi.Char> product;

  /// < Product ID for this device
  @ffi.Uint16()
  external int product_id;

  /// < Bugs, device specifics etc
  @ffi.Uint32()
  external int device_flags;
}

typedef LIBMTP_device_entry_t = LIBMTP_device_entry_struct;

/// A data structure to hold a raw MTP device connected
/// to the bus.
final class LIBMTP_raw_device_struct extends ffi.Struct {
  /// < The device entry for this raw device
  external LIBMTP_device_entry_t device_entry;

  /// < Location of the bus, if device available
  @ffi.Uint32()
  external int bus_location;

  /// < Device number on the bus, if device available
  @ffi.Uint8()
  external int devnum;
}

typedef LIBMTP_raw_device_t = LIBMTP_raw_device_struct;
typedef LIBMTP_error_t = LIBMTP_error_struct;

/// A data structure to hold errors from the library.
final class LIBMTP_error_struct extends ffi.Struct {
